// })

// =============================================================== add button ====================================
$(document).ready(function(){
	
	$("#Fund_Type").closest(".card").append(
    	"<div class='text-right'>"+
    	    "<div class='btn btn-primary' id='Fund_Type_add'><i class='fas fa-plus align-middle'></i><span class='align-middle ml-1'>Add</span></div>"+
    	"</div>"
	);
});

//================================================== function process crud =================================================
window['saveItem'] = function save (){
	//$('#Fund_type_modal :input:not(#fty_status_modal, #fty_fund_ID, #fty_remark_modal)').attr('required',true);
	if(formValidate('#Fund_type_modal')){
		$.ajax({
			type: "POST",
			dataType: 'json',
			url: "api/ANIS_FUND_TYPE?FT_process=1",
			data : $('#Fund_type_modal :input').serializeJson(),
			success: function(data){
				if(data.status=="ok"){
					showModal({
						type: "alert",
						content: LANG_INSERT_SUCCESS, 
						size: "sm",
					});
					$('#Fund_Type').DataTable().ajax.reload()
					$('#Fund_type_modal').modal("hide");
				}
				else if(data.status=="ko"){
					showModal({
						type: "alert",
						content: data.errorMessage || data.message || LANG_PROCESS_ERROR,  
						size: "sm"
					});    
				}
			}
		});
	}
	else{
		showModal({
			type: "alert",
			content: LANG_VALIDATE_VALUEMISSING,
			size: "sm"
		});    
	}
}

//================================================== onclick add
//$('#Fund_Type_add').click(function(){
$(document).on('click', '#Fund_Type_add', function(){

	$('#fty_status_modal').val('1').change();
	//$('#Fund_type_modal :input:not(#fty_status_modal)').attr('required',false);
	$('#Fund_type_modal :input:not(#fty_status_modal)').val('').change();
	$('#inputLabel_fty_fund_ID, #inputArea_fty_fund_ID').hide();
	$('#Fund_type_modal').find('.modal-header').text(labelModal[i]);
	$('#Fund_type_modal').modal('show');
})

//=============================================onclick edit (utk edit button)
edit = function (targetID){
	
	$.get("api/ANIS_FUND_TYPE?FT_modal=form&id=" + targetID, function (data) {

		$('#inputLabel_fty_fund_ID, #inputArea_fty_fund_ID').hide();
		$('#fty_fund_ID').val(data.ID);
		$('#fty_fund_type_modal').val(data.TYPE);
		$('#fty_fund_desc_modal').val(data.DESCRIPTION);
		$('#fty_fund_desc_eng_modal	').val(data.DESCRIPTIONENG);
		$('#fty_basis_modal').val(data.BASIS);
		$('#fty_remark_modal').val(data.REMARK);
		$('#fty_status_modal').val(data.STATUS).change();

		$('#Fund_type_modal').find('.modal-header').text(labelModal[1]);
		$('#Fund_type_modal').modal('show');
	});
}

