					$('#Fund_Type').DataTable().ajax.reload()
					$('#Fund_type_modal').modal("hide");
				}
				else if(data.status=="ko"){
					showModal({
						type: "alert",
						content: data.errorMessage || data.message || LANG_PROCESS_ERROR,  
						size: "sm"
					});    
				}
			}
		});
	}
	else{
		showModal({
			type: "alert",
			content: LANG_VALIDATE_VALUEMISSING,
			size: "sm"
		});    
	}
}

